- (void)setupData {
    // 设置倒计时文本
    self.daysLabel.text = [NSString stringWithFormat:@"%ld天", self.CountDown.RemainingDays];

    self.headerView.titleLabel.text = self.CountDown.Title;

    self.titleLabel.text = self.CountDown.Title;

    NSComparisonResult result = [self.CountDown CompareDaysResult];
    if (result == NSOrderedAscending) {
        self.state.text = @"已过期";
    }  else { // 相等
        self.state.text = @"进行中";
    }

    NSDateFormatter *formatter = [[NSDateFormatter alloc] init];
    formatter.dateFormat = @"'目标日期: 'yyyy-MM-dd";
    NSString *dateString = [formatter stringFromDate:self.CountDown.TargetDate];
    self.targetDateLabel.text = dateString;

    self.backgroundView.image = [UIImage imageNamed:self.CountDown.BackGroundName];

    self.timeLabel.text = @"15:30:59";

}

