- (void)zoomOutButtonClicked:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    if (!self.handleView.pictureView.image) {
        [self showAlertWithTitle:@"Tip" message:@"Please select an image first"];
        return;
    }
    FullScreenImageViewController *fullScreenVC = [[FullScreenImageViewController alloc] init];
    fullScreenVC.fullImage = self.handleView.pictureView.image;
    fullScreenVC.modalPresentationStyle = UIModalPresentationFullScreen;
    fullScreenVC.modalTransitionStyle = UIModalTransitionStyleCrossDissolve; // Smooth fade transition
    [self presentViewController:fullScreenVC animated:YES completion:nil];
}

- (void)cleanButtonClicked:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    [self clearSelectedImage];
}

- (void)colorButtonClicked:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    ColorPickerView *colorPicker = [[ColorPickerView alloc] initWithFrame:CGRectMake(0, CGRectGetMaxY(self.view.bounds) - 360, CGRectGetWidth(self.view.bounds), 300)];
    colorPicker.colorSelectedCallback = ^(UIColor *selectedColor) {
        sender.backgroundColor = selectedColor;
        [self updateWatermark];
    };
    [self.view addSubview:colorPicker];
}

- (void)requestPhotoLibraryAccess {
    PHAuthorizationStatus status = [PHPhotoLibrary authorizationStatus];
    if (status == PHAuthorizationStatusAuthorized) {
        [self openImagePicker]; // Already authorized
    } else if (status == PHAuthorizationStatusNotDetermined) {
        [PHPhotoLibrary requestAuthorization:^(PHAuthorizationStatus status) {
            if (status == PHAuthorizationStatusAuthorized) {
                dispatch_async(dispatch_get_main_queue(), ^{
                    [self openImagePicker];
                });
            }
        }];
    } else {
        // Access denied
        [self showPermissionAlert];
    }
}

- (void)openImagePicker {
    UIImagePickerController *imagePicker = [[UIImagePickerController alloc] init];
    imagePicker.sourceType = UIImagePickerControllerSourceTypePhotoLibrary;
    imagePicker.delegate = self;
    [self presentViewController:imagePicker animated:YES completion:nil];
}

- (void)saveImageToPhotoLibrary {
    UIImage *imageToSave = self.handleView.pictureView.image;
    if (!imageToSave) {
        [self showAlertWithTitle:@"Save Failed" message:@"Please select an image first"];
        return;
    }
    PHAuthorizationStatus status = [PHPhotoLibrary authorizationStatus];
    switch (status) {
        case PHAuthorizationStatusAuthorized: {
            [self performSaveImage:imageToSave];
            break;
        }
        case PHAuthorizationStatusNotDetermined: {
            [PHPhotoLibrary requestAuthorization:^(PHAuthorizationStatus newStatus) {
                if (newStatus == PHAuthorizationStatusAuthorized) {
                    dispatch_async(dispatch_get_main_queue(), ^{
                        [self performSaveImage:imageToSave];
                    });
                }
            }];
            break;
        }
        default: {
            [self showPermissionAlert];
            break;
        }
    }
}

- (void)clearSelectedImage {
    self.handleView.pictureView.image = nil;
    self.handleView.tipLabel.hidden = NO;
}

- (void)dismissKeyboard {
    [self.view endEditing:YES]; // End all editing
}

- (BOOL)textFieldShouldReturn:(UITextField *)textField {
    [textField resignFirstResponder]; // Dismiss keyboard
    return YES;
}

#pragma mark - UIImagePickerControllerDelegate

- (void)imagePickerController:(UIImagePickerController *)picker didFinishPickingMediaWithInfo:(NSDictionary<UIImagePickerControllerInfoKey, id> *)info {
    [picker dismissViewControllerAnimated:YES completion:nil];

    // Get selected image
    self.originalImage = info[UIImagePickerControllerOriginalImage];
    if (self.originalImage) {
        // Display in PictureHandleView
        self.handleView.pictureView.image = self.originalImage;
        self.handleView.tipLabel.hidden = YES;
        [self updateWatermark];
    }
}

- (void)imagePickerControllerDidCancel:(UIImagePickerController *)picker {
    [picker dismissViewControllerAnimated:YES completion:nil];
}

